#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_check_result_display_passed() {
        let result = CheckResult::Passed("Database accessible".to_string());
        let ctx = OutputContext::rich();
        let display = format_check_result(&result, &ctx);
        // Rich mode should include colored checkmark
        assert!(display.contains("✓") || display.contains("passed"));
    }

    #[test]
    fn test_check_result_display_warning() {
        let result = CheckResult::Warning("2 issues have invalid refs".to_string());
        let ctx = OutputContext::rich();
        let display = format_check_result(&result, &ctx);
        assert!(display.contains("⚠") || display.contains("warning"));
    }

    #[test]
    fn test_check_result_display_failed() {
        let result = CheckResult::Failed("Cannot open database".to_string());
        let ctx = OutputContext::rich();
        let display = format_check_result(&result, &ctx);
        assert!(display.contains("❌") || display.contains("failed"));
    }

    #[test]
    fn test_diagnosis_summary_counts() {
        let results = vec![
            CheckResult::Passed("Check 1".to_string()),
            CheckResult::Passed("Check 2".to_string()),
            CheckResult::Warning("Check 3".to_string()),
            CheckResult::Failed("Check 4".to_string()),
        ];
        let summary = DiagnosisSummary::from_results(&results);
        assert_eq!(summary.passed, 2);
        assert_eq!(summary.warnings, 1);
        assert_eq!(summary.failed, 1);
    }

    #[test]
    fn test_json_mode_structured_output() {
        let results = vec![
            CheckResult::Passed("DB ok".to_string()),
            CheckResult::Warning("Sync issue".to_string()),
        ];
        let ctx = OutputContext::json();
        let output = format_diagnosis(&results, &ctx);
        // Should produce valid JSON
        let parsed: serde_json::Value = serde_json::from_str(&output).unwrap();
        assert!(parsed["checks"].is_array());
        assert!(parsed["summary"]["passed"].is_number());
    }

    #[test]
    fn test_exit_code_based_on_results() {
        // All passed = exit 0
        let all_passed = vec![CheckResult::Passed("ok".to_string())];
        assert_eq!(compute_exit_code(&all_passed), 0);

        // Warnings only = exit 0 (non-blocking)
        let with_warnings = vec![
            CheckResult::Passed("ok".to_string()),
            CheckResult::Warning("warn".to_string()),
        ];
        assert_eq!(compute_exit_code(&with_warnings), 0);

        // Any failures = exit 1
        let with_failure = vec![
            CheckResult::Passed("ok".to_string()),
            CheckResult::Failed("critical".to_string()),
        ];
        assert_eq!(compute_exit_code(&with_failure), 1);
    }
}
